INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('04-ky-nang-ca-nhan',1,4,'KỸ NĂNG CÁ NHÂN','Cac ky nang ca nhan can co de xay dung Empire',4,'draft','2026-06-20T06:55:04Z','2026-06-20T06:55:04Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('06aa4bfb-2d95-48d1-b549-f746dce7d965','04-ky-nang-ca-nhan',NULL,2,'Mục đích của chương','muc-ich-cua-chuong',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('93268049-c2b9-417d-b2f7-810f00e1cb0e','06aa4bfb-2d95-48d1-b549-f746dce7d965',0,'text','Chương này không nhằm giải thích lại khái niệm, mà nhằm hướng dẫn cách **dùng ROADMAP để xây một bộ roadmap riêng cho từng doanh nghiệp**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('97fc8db3-9445-4526-b3e9-c84693edbb30','06aa4bfb-2d95-48d1-b549-f746dce7d965',1,'text','Mỗi doanh nghiệp sẽ có bối cảnh, quy mô, năng lực và vấn đề khác nhau, nên điều quan trọng không phải là sao chép mẫu có sẵn, mà là đi qua đúng 7 tầng để tạo ra bộ khung phù hợp với chính mình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a111ed89-a8bb-4255-a22f-2cb7ae403a8a','06aa4bfb-2d95-48d1-b549-f746dce7d965',2,'text','Tinh thần xuyên suốt là: làm rõ tới đâu, đi được tới đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2b8c9d13-b639-45b1-860d-60b0452e6e9c','04-ky-nang-ca-nhan',NULL,2,'Nguyên tắc thực hành','nguyen-tac-thuc-hanh',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9a3b876f-2b03-47db-932b-b6f12330c8d9','2b8c9d13-b639-45b1-860d-60b0452e6e9c',3,'text','Muốn thực hành ROADMAP đúng, cần giữ 3 nguyên tắc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('71ce782c-212f-48eb-8a52-ef60c3dfe297','2b8c9d13-b639-45b1-860d-60b0452e6e9c',4,'text','- Thứ nhất, không bắt đầu bằng giải pháp, mà bắt đầu bằng căn nguyên và bản sắc.- Thứ hai, mỗi tầng phải tạo ra một đầu ra cụ thể để tầng sau có cái mà bám vào.- Thứ ba, R.O.A.D.M.A.P phải là một vòng lặp sống, không phải một bản kế hoạch treo tường.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('057cab44-9629-4fd9-9f11-5ee47e9e5c4e','04-ky-nang-ca-nhan',NULL,2,'Cách đi 7 tầng','cach-i-7-tang',2,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b8f4fc24-6b9f-480b-bab1-08e9ccc0f418','04-ky-nang-ca-nhan','057cab44-9629-4fd9-9f11-5ee47e9e5c4e',3,'R - ROOTS','r-roots',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('00bb1885-9f5f-4694-aa83-c616554e2133','b8f4fc24-6b9f-480b-bab1-08e9ccc0f418',5,'text','- Bắt đầu bằng việc xác định tổ chức là ai và vì sao nó tồn tại.- Ở tầng này, hãy làm rõ sứ mệnh, bản sắc, giá trị gốc và operating code nền.- Nếu ROOTS chưa xong thì chưa nên bàn tới tăng trưởng, vì chưa có gốc thì mọi mở rộng đều dễ lệch.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f4b51f57-9b6a-498c-9db1-747b86c5a4fe','04-ky-nang-ca-nhan','057cab44-9629-4fd9-9f11-5ee47e9e5c4e',3,'O - ONE LIGHT','o-one-light',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('28de2911-a2de-40de-b74f-79fdf56fb20a','f4b51f57-9b6a-498c-9db1-747b86c5a4fe',6,'text','- Sau khi có gốc, cần chốt ánh sáng chung để toàn hệ thống cùng hướng.- Tầng này dùng để xác định chuẩn mực đạo đức, lằn ranh đỏ, và hệ giá trị dẫn đường cho quyết định.- Khi ONE LIGHT rõ, tổ chức sẽ bớt mâu thuẫn nội bộ vì mọi người có chung tiêu chuẩn để quay về.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('07872ac6-3310-48c5-9d7e-43c921dc058a','04-ky-nang-ca-nhan','057cab44-9629-4fd9-9f11-5ee47e9e5c4e',3,'A - AWAKEN','a-awaken',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('145889b7-8736-4978-8f4f-f62e569c3db2','07872ac6-3310-48c5-9d7e-43c921dc058a',7,'text','- Tầng này dùng để nhìn thật tình trạng hiện tại.- Tổ chức cần audit nội bộ, quan sát thị trường, vẽ bản đồ khoảng cách và nhận diện tín hiệu sớm.- Nếu không AWAKEN, roadmap sẽ được viết trên ảo giác chứ không phải trên thực tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cee79878-fe3b-4160-89d6-239a264955cc','04-ky-nang-ca-nhan','057cab44-9629-4fd9-9f11-5ee47e9e5c4e',3,'D - DEEPEN','d-deepen',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('09a2c4a0-1011-49ef-8faa-2edc08106222','cee79878-fe3b-4160-89d6-239a264955cc',8,'text','- Khi đã biết vấn đề là gì, phải chuẩn hóa nó thành quy trình.- Tầng này biến nhận thức thành SOP, checklist, vai trò, trách nhiệm và tiêu chuẩn thực thi.- Đây là nơi roadmap bắt đầu có hình hài vận hành thật.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9f9ca449-9ae2-40e1-97de-5f2cf0d8b333','04-ky-nang-ca-nhan','057cab44-9629-4fd9-9f11-5ee47e9e5c4e',3,'M - MATURE','m-mature',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6c81aa23-bf2d-43cf-aa7c-9a1855c27d0b','9f9ca449-9ae2-40e1-97de-5f2cf0d8b333',9,'text','- Sau chuẩn hóa là làm cho hệ thống chín hơn.- MATURE dùng để chỉnh nhịp, tăng độ ăn khớp, giảm ma sát, và tạo đà cho tổ chức vận hành bền hơn.- Tầng này rất quan trọng vì một hệ thống có thể chạy nhanh nhưng chưa chắc đã chín.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('795b7e90-de38-4bb1-945c-ed5f651aa8dd','04-ky-nang-ca-nhan','057cab44-9629-4fd9-9f11-5ee47e9e5c4e',3,'A - ALIGN','a-align',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2955fe50-c0a8-4d27-a938-b5d1e9cbbe54','795b7e90-de38-4bb1-945c-ed5f651aa8dd',10,'text','- Tầng này dùng để nối chiến lược với nguồn lực và vận hành.- Mục tiêu, vai trò, KPI, nguồn lực và tiến độ phải được đồng bộ lại để tránh lệch pha.- Nếu không ALIGN, tổ chức sẽ có kế hoạch rất hay nhưng thực địa lại chạy theo một logic khác.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('47e9ec47-c322-43de-aa87-58ced331cf15','04-ky-nang-ca-nhan','057cab44-9629-4fd9-9f11-5ee47e9e5c4e',3,'P - PROSPER','p-prosper',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ddfb2c8d-8a4a-471f-b4cf-910299169fb6','47e9ec47-c322-43de-aa87-58ced331cf15',11,'text','- Cuối cùng là tạo vòng sinh sôi, tái đầu tư và làm mới.- Tầng này biến kết quả thành nhiên liệu cho chu kỳ tiếp theo, thay vì để thành quả bị tiêu hao.- PROSPER là đích của một roadmap sống: tăng trưởng nhưng vẫn có khả năng tự RENEW.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d7726279-d590-4072-a423-3b926ef57711','04-ky-nang-ca-nhan',NULL,2,'Bộ câu hỏi thực hành','bo-cau-hoi-thuc-hanh',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1773ac63-352e-4503-bf8b-a4af6cf24e82','d7726279-d590-4072-a423-3b926ef57711',12,'text','Mỗi tầng nên có 3 nhóm câu hỏi: **chẩn đoán, thiết kế, triển khai**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8e4c53c3-ac6a-4938-9701-a4237a666b18','d7726279-d590-4072-a423-3b926ef57711',13,'text','*Ví dụ ở ROOTS, câu hỏi chẩn đoán là “chúng ta là ai”; câu hỏi thiết kế là “bản sắc nào cần chốt”; câu hỏi triển khai là “ai chịu trách nhiệm đóng gói thành tuyên ngôn”. *',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e898b8e7-911b-438c-8954-512390194dc2','d7726279-d590-4072-a423-3b926ef57711',14,'text','Cách hỏi này giúp roadmap không bị trôi sang triết lý chung chung mà luôn gắn với hành động cụ thể.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b6fef294-b63b-40a1-9dd3-2f6feedb1708','04-ky-nang-ca-nhan',NULL,2,'Bộ công cụ cần có','bo-cong-cu-can-co',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e0bc1262-df04-4330-9d40-7a24721ec581','b6fef294-b63b-40a1-9dd3-2f6feedb1708',15,'text','Để viết được **R.O.A.D.M.A.P** cho từng doanh nghiệp, nên chuẩn bị 6 công cụ cố định.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5c082977-c74e-457b-8d2e-0bdfc537d05d','b6fef294-b63b-40a1-9dd3-2f6feedb1708',16,'text','- Workshop form để khai mở ROOTS và ONE LIGHT.- Audit form để làm rõ AWAKEN.- SOP template để chuẩn hóa DEEPEN.- Review sheet để theo dõi MATURE.- KPI/resource map để làm ALIGN.- Growth loop canvas để thiết kế PROSPER.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('35bb4a07-8242-4071-b2d7-79198cf7963e','04-ky-nang-ca-nhan',NULL,2,'Đầu ra cuối cùng','au-ra-cuoi-cung',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9e5e0cd6-f710-4317-9ff6-0209b59a39ef','35bb4a07-8242-4071-b2d7-79198cf7963e',17,'text','Sau khi đi đủ 7 tầng, doanh nghiệp phải có một R.O.A.D.M.A.P hoàn chỉnh gồm 7 phần.
Mỗi phần phải trả lời được: tổ chức là ai, vận hành theo nguyên tắc nào, đang ở đâu, cần chuẩn hóa gì, cần chín hơn ở đâu, cần đồng bộ ra sao và cần tăng trưởng bằng cơ chế nào.
Khi đó roadmap không còn là kế hoạch, mà là **bản đồ vận hành và tiến hóa** của doanh nghiệp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9a581dfb-8a69-4f91-8ce6-2a4b9ec0b1b5','04-ky-nang-ca-nhan',NULL,2,'Cách dùng trong thực tế','cach-dung-trong-thuc-te',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('42f454bf-0c2e-478b-95d9-cb53ae896eb0','9a581dfb-8a69-4f91-8ce6-2a4b9ec0b1b5',18,'text','Một buổi triển khai ROADMAP nên đi theo trình tự: chốt nền, soi thực trạng, chọn ưu tiên, chuẩn hóa, đồng bộ, và thiết kế vòng tăng trưởng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c8d8c16d-4019-4175-a5a1-d07ad4806756','9a581dfb-8a69-4f91-8ce6-2a4b9ec0b1b5',19,'text','Với doanh nghiệp nhỏ, có thể làm gọn trong 1–2 buổi workshop; với doanh nghiệp lớn, nên tách thành nhiều vòng để đào sâu từng tầng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('33f660ad-0309-40eb-aafc-31660ed86463','9a581dfb-8a69-4f91-8ce6-2a4b9ec0b1b5',20,'text','Quan trọng nhất là sau mỗi buổi phải có đầu ra viết được, đo được và giao việc được.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5cd546c2-1c37-4e31-8b1a-023902bf0b86','04-ky-nang-ca-nhan',NULL,2,'XÁC ĐỊNH ROOTS','xac-inh-roots',14,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('401fe6c9-8763-4772-8f56-410264094467','04-ky-nang-ca-nhan','5cd546c2-1c37-4e31-8b1a-023902bf0b86',3,'R - RADICLEKhai quật rễ chính của hệ thốngRadicle là “mầm rễ chủ” của tổ chức. Đây là nơi xác định giá trị lõi, bản sắc nền tảng và lý do tồn tại dài hạn của doanh nghiệp. Trả lời cho câu hỏi "Chúng ta là ai?"Việc cần làm:Tổ chức các phiên làm việc chiến lược với Founder và đội ngũ lãnh đạo nòng cốt, có thể gọi là:Founder’s Vision Session – Phiên xác lập DNA tổ chứcMục tiêu của phiên này là bóc tách những điều sâu nhất mà tổ chức thật sự tin, thật sự bảo vệ và thật sự muốn theo đuổi.Câu hỏi cốt lõiNếu doanh thu không còn là áp lực duy nhất, vì sao tổ chức này vẫn xứng đáng tồn tại?Điều gì khiến tổ chức này khác biệt so với những đơn vị cùng ngành?Đâu là 3 đến 5 giá trị mà tổ chức sẵn sàng bảo vệ đến cùng, dù có phải đánh đổi lợi ích ngắn hạn?Điều gì Founder không muốn đánh mất khi doanh nghiệp lớn lên?Nếu một ngày tổ chức phát triển thành hệ thống lớn, đâu là tinh thần gốc bắt buộc phải được giữ lại?Kết quả cần đạt:Tuyên bố sứ mệnh mang tính bản sắc.Câu trả lời rõ ràng cho câu hỏi:“Tổ chức này sinh ra để phụng sự điều gì?”','r-radiclekhai-quat-re-chinh-cua-he-thongradicle-la-mam-re-chu-cua-to-chuc-ay-la-',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('887e7492-c596-4183-a759-c961101c150c','401fe6c9-8763-4772-8f56-410264094467',21,'image',NULL,'book/04-ky-nang-ca-nhan/9e531744-4f61-442c-992b-8fccba3f0b85-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cc0f83f2-f044-493d-9af2-35302fd1ffe6','04-ky-nang-ca-nhan','5cd546c2-1c37-4e31-8b1a-023902bf0b86',3,'O - OPERATING CODELập mã nguồn vận hành:Operating Code là bộ nguyên tắc vận hành cốt lõi của tổ chức. Đây chưa phải là SOP chi tiết. SOP sẽ nằm ở tầng DEEPEN. Operating Code là tầng cao hơn SOP: nó định hướng cách toàn hệ thống suy nghĩ, phối hợp, xử lý xung đột và ra quyết định.Nếu Radicle trả lời câu hỏi “Chúng ta là ai?”, thì Operating Code trả lời câu hỏi:“Chúng ta vận hành theo nguyên tắc nào?”Hành động cần thực hiện:Quan sát lại cách tổ chức đang làm việc, ra quyết định, xử lý khách hàng, xử lý sai sót và phối hợp nội bộ. Sau đó đúc kết thành một bộ nguyên tắc vận hành có tính nền tảng.Có thể gọi đây là:Hiến pháp vận hành của tổ chứcCâu hỏi cốt lõi:Khi không có khách hàng trước mặt, chúng ta đối xử với nhau như thế nào?Khi có xung đột giữa lợi ích kinh doanh và tiêu chuẩn chuyên môn, tổ chức sẽ chọn hướng nào?Khi xảy ra lỗi, chúng ta tìm người để đổ lỗi hay tìm nguyên nhân để cải tiến hệ thống?Khi không có Founder ở đó, đội ngũ sẽ dựa vào nguyên tắc nào để tự ra quyết định?Đâu là những nguyên tắc không được phép vi phạm trong vận hành?Kết quả cần đạtBộ 5 Nguyên tắc vận hành tối cao, ví dụ:Chuyên môn là nền tảng.Không đánh đổi tiêu chuẩn chuyên môn để lấy lợi ích ngắn hạn.Minh bạch trong dữ liệu.Mọi quyết định quan trọng phải dựa trên thông tin rõ ràng, không dựa trên cảm tính mơ hồ.Phối hợp không đổ lỗi.Khi có vấn đề, ưu tiên sửa hệ thống trước khi quy kết con người.Khách hàng/bệnh nhân là trung tâm.Mọi điểm chạm phải hướng đến sự an toàn, rõ ràng và tin cậy.Tự cải tiến mỗi ngày.Không chấp nhận trạng thái trì trệ, lặp lại lỗi cũ mà không học hỏi.','o-operating-codelap-ma-nguon-van-hanhoperating-code-la-bo-nguyen-tac-van-hanh-co',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f542c649-80a6-48fd-a8aa-5b94d604a43b','cc0f83f2-f044-493d-9af2-35302fd1ffe6',22,'image',NULL,'book/04-ky-nang-ca-nhan/978bd3b2-2e88-46c9-9a21-e82f51bda992-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d73fbd4d-dfa6-4bc7-b137-5f4a43e6e50b','04-ky-nang-ca-nhan','5cd546c2-1c37-4e31-8b1a-023902bf0b86',3,'O - OUTREACHThiết kế tầm lan tỏa:Outreach là cách ROOTS đi ra bên ngoài. Một tổ chức không chỉ tồn tại bằng những điều nó tin ở bên trong, mà còn bằng cách nó lan tỏa giá trị đó ra cộng đồng, khách hàng, thị trường và hệ sinh thái xung quanh.Outreach không đơn giản là marketing.Outreach là sự mở rộng ảnh hưởng dựa trên giá trị thật.Hành động cần thực hiện:Định vị tài sản thương hiệu, xác định thông điệp cốt lõi và lập bản đồ các kênh tiếp cận dựa trên niềm tin, tri thức và giá trị mà tổ chức muốn lan tỏa.Câu hỏi cốt lõi:Tổ chức sẽ mang tri thức, giải pháp hoặc niềm tin gì để đóng góp cho cộng đồng?Chúng ta muốn khách hàng nhớ đến mình vì điều gì?Nội dung truyền thông của chúng ta đang phản ánh giá trị lõi hay chỉ đang chạy theo xu hướng?Hình mẫu thương hiệu của chúng ta là gì: Người chăm sóc, Người thông thái, Người kiến tạo hay Người dẫn đường?Đâu là những kênh giúp tổ chức lan tỏa giá trị một cách bền vững nhất?Kết quả cần đạt:Chiến lược định vị thương hiệu.Bộ thông điệp cốt lõi.Bộ từ khóa thương hiệu.Bản đồ kênh tiếp cận khách hàng.Nguyên tắc truyền thông dựa trên sự tin cậy, không dựa trên chiêu trò ngắn hạn.Tầm nhìn tổ chức trong 1-3-5-10-20 năm','o-outreachthiet-ke-tam-lan-toaoutreach-la-cach-roots-i-ra-ben-ngoai-mot-to-chuc-',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a3cae0a7-0f07-4985-9823-e339d8712df1','d73fbd4d-dfa6-4bc7-b137-5f4a43e6e50b',23,'image',NULL,'book/04-ky-nang-ca-nhan/1270b9eb-003c-4db3-b0c2-de4359c15d20-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3c4d1ffa-3791-4e95-ae34-332ace295252','04-ky-nang-ca-nhan','5cd546c2-1c37-4e31-8b1a-023902bf0b86',3,'T - TENACITYĐo lường lòng kiên định:Tenacity là sức bền của tổ chức. Đây là khả năng bám mục tiêu, giữ kỷ luật, không vỡ trận khi gặp áp lực và không đánh mất bản sắc khi phát triển.Một tổ chức có thể có giá trị lõi rất đẹp, nhưng nếu thiếu Tenacity, những giá trị đó sẽ tan rã khi gặp khủng hoảng, cạnh tranh, suy giảm dòng tiền hoặc áp lực tăng trưởng.Hành động cần thực hiện:Xác định mục tiêu dài hạn, chỉ số ngôi sao Bắc Đẩu và bộ nguyên tắc ứng biến khi tổ chức gặp khủng hoảng.Câu hỏi cốt lõi:Mục tiêu dài hạn 5 năm và 10 năm của tổ chức là gì?Chỉ số nào phản ánh rõ nhất việc tổ chức đang đi đúng hướng?Khi thị trường suy giảm, điều gì giữ cho đội ngũ không rã đám?Khi doanh thu chịu áp lực, đâu là những giá trị không được phép bán rẻ?Khi gặp khủng hoảng truyền thông, sự cố vận hành hoặc áp lực cạnh tranh, tổ chức sẽ dựa vào nguyên tắc nào để đứng vững?Kết quả cần đạt:Giá trị cốt lõi "Core Value" là gìNhững tính cách của thành viên tổ chức là gì "Core Character"Bộ nguyên tắc giữ vững bản sắc khi gặp áp lực.Bộ quy tắc ứng biến khủng hoảng.Câu trả lời rõ ràng cho câu hỏi:“Điều gì giúp tổ chức không mất phương hướng khi gặp bão?”','t-tenacityo-luong-long-kien-inhtenacity-la-suc-ben-cua-to-chuc-ay-la-kha-nang-ba',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4e3d803b-030c-4c54-a28a-60e42c2bd157','3c4d1ffa-3791-4e95-ae34-332ace295252',24,'image',NULL,'book/04-ky-nang-ca-nhan/db490bdf-2bd5-468e-8b0c-aea5e771c364-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7b8605b1-ecba-4516-91e2-c9f894f3dd58','04-ky-nang-ca-nhan','5cd546c2-1c37-4e31-8b1a-023902bf0b86',3,'S - STANDARDIZED STATEMENTĐúc kết thành tuyên bố chuẩn hóaStandardized Statement là bước đóng gói toàn bộ ROOTS thành một tuyên bố rõ ràng, ngắn gọn và có thể sử dụng trong tài liệu, đào tạo, truyền thông, tuyển dụng và vận hành.Nếu không có Standardized Statement, ROOTS sẽ dễ bị hiểu khác nhau giữa các phòng ban.Nếu có tuyên bố chuẩn, toàn hệ thống có một câu gốc để cùng ghi nhớ, cùng truyền đạt và cùng thực thi.Hành động cần thực hiệnCô đọng toàn bộ chất liệu từ Radicle, Operating Code, Outreach và Tenacity thành một văn bản ngắn, có nhịp điệu, dễ hiểu, dễ thuộc và dễ ứng dụng.Kết quả cần đạtMột bản Manifesto – Tuyên ngôn văn hóa của tổ chức, dài không quá 200 chữ.Tuyên ngôn này cần trả lời được 5 ý:Chúng ta là ai?Chúng ta tin vào điều gì?Chúng ta vận hành theo nguyên tắc nào?Chúng ta phụng sự ai?Chúng ta sẽ kiên định với điều gì trong dài hạn?','s-standardized-statementuc-ket-thanh-tuyen-bo-chuan-hoastandardized-statement-la',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('117b3a8a-bc91-4f50-bf62-d13892953dfa','7b8605b1-ecba-4516-91e2-c9f894f3dd58',25,'image',NULL,'book/04-ky-nang-ca-nhan/a5ae6474-8186-4ece-a0c3-6003c85a0aeb-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f4b50d96-7972-4750-ad3f-c35448c1b21b','04-ky-nang-ca-nhan',NULL,2,'XÁC ĐỊNH ONE LIGHT','xac-inh-one-light',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b0a57285-07c0-4ce9-8a62-d234767eb752','f4b50d96-7972-4750-ad3f-c35448c1b21b',26,'text','ONE LIGHT là tầng **định hướng và chuẩn mực**, nơi tổ chức thống nhất một lòng, giữ phẩm giá và không thỏa hiệp với những giá trị đạo đức cốt lõi. Tầng này giúp tổ chức có một “ngọn đèn soi đường” để mọi quyết định không bị lệch khỏi bản sắc ban đầu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('259c6171-0ac0-458c-92fc-707d0f001ba1','f4b50d96-7972-4750-ad3f-c35448c1b21b',27,'text','ONE LIGHT làm nhiệm vụ chuyển bản sắc của ROOTS thành hệ chuẩn sống được trong thực tế. Nếu ROOTS trả lời “chúng ta là ai”, thì ONE LIGHT trả lời “chúng ta sẽ sống và làm việc theo chuẩn nào”.
Tầng này giữ cho tổ chức không chỉ đúng về lý tưởng, mà còn đúng về cách hành xử, cách ra quyết định và cách đối diện với cám dỗ tăng trưởng. Nó cũng là lớp giúp đội ngũ đồng tâm, cùng một trục giá trị, thay vì mỗi người hiểu văn hóa theo một kiểu khác nhau.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1137301d-2386-464d-8811-c176951bfb42','f4b50d96-7972-4750-ad3f-c35448c1b21b',28,'text','ONE là phần thống nhất chung của mọi tổ chức: một lòng, cao quý, đạo đức; còn LIGHT là bộ ánh sáng riêng mà mỗi tổ chức cần tự xác định để soi đường cho bản sắc, sứ mệnh và cách vận hành của mình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('08efba2c-84c0-4959-be50-d9e1abf6de88','04-ky-nang-ca-nhan','f4b50d96-7972-4750-ad3f-c35448c1b21b',3,'Tiêu chuẩn của một bộ LIGHT là gì?','tieu-chuan-cua-mot-bo-light-la-gi',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('60f0eb60-a809-4555-b8b7-258564635696','08efba2c-84c0-4959-be50-d9e1abf6de88',29,'text','Bộ LIGHT của một tổ chức phải là **bộ ánh sáng riêng**, được xác định theo ngành nghề của chính tổ chức đó. Nó không phải là bản sao của nơi khác, mà là hệ giá trị soi đường phù hợp nhất với con đường phát triển của tổ chức này.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('30c7aba2-8ecf-4265-9fc0-21bea523182f','08efba2c-84c0-4959-be50-d9e1abf6de88',30,'text','**Một bộ LIGHT đạt chuẩn cần có 4 tiêu chí:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('beb2685b-eabe-4dd5-921e-fb6352f13ba5','08efba2c-84c0-4959-be50-d9e1abf6de88',31,'text','- **Rõ ràng ****- **Mỗi giá trị phải được gọi tên cụ thể, không mập mờ, không đa nghĩa.- **Khả thi ****- **Giá trị đó phải có thể chuyển thành hành vi thực tế, không chỉ tồn tại trên khẩu hiệu.- **Nhất quán**** - **Bộ LIGHT phải đi cùng một trục với ONE, không được mâu thuẫn với phẩm giá và đạo đức chung.- **Đặc trưng**** - **Bộ LIGHT phải phản ánh được linh hồn riêng của tổ chức, để khi nhìn vào là nhận ra ngay bản sắc của nó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6754d061-e517-48bf-a000-f16aa8e54c49','08efba2c-84c0-4959-be50-d9e1abf6de88',32,'text','**LIGHT không phải là điều tốt đẹp nói chung**, mà là **bộ giá trị soi đường riêng được lựa chọn có chủ đích** để dẫn tổ chức đi đúng hướng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7ba7fb38-1f85-4f57-92a6-3f0bee7209de','08efba2c-84c0-4959-be50-d9e1abf6de88',33,'image',NULL,'book/04-ky-nang-ca-nhan/cda64980-9eea-478b-b8fe-4b0a7020978d-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('03e6a9b4-1298-4b97-8b30-94f7b3199c74','08efba2c-84c0-4959-be50-d9e1abf6de88',34,'text','**Gợi ý LIGHT:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('079f6799-932d-462e-a386-d35c489d6ddc','08efba2c-84c0-4959-be50-d9e1abf6de88',35,'image',NULL,'book/04-ky-nang-ca-nhan/fbc5fbd7-a0fc-4ccd-937d-a499ee5ea7e8-img07.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('44e24f89-79f8-4b24-825a-ee65ba666645','04-ky-nang-ca-nhan','f4b50d96-7972-4750-ad3f-c35448c1b21b',3,'Hành động cần thực hiện','hanh-ong-can-thuc-hien',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('90cbc076-0404-46a2-bfd2-3008955f0a5a','44e24f89-79f8-4b24-825a-ee65ba666645',36,'text','- Xác lập bộ giá trị chuẩn của tổ chức, gồm các nguyên tắc cốt lõi không thể thỏa hiệp.- Chuyển các giá trị đó thành hành vi cụ thể nên làm và không được làm.- Đào tạo nội bộ để nhân sự mới và nhân sự cũ đều hiểu cùng một chuẩn.- Rà soát các chính sách, SOP và thông điệp truyền thông để bảo đảm chúng không lệch khỏi chuẩn đạo đức và khí chất tổ chức.- Thiết lập một “điểm neo” cho mọi quyết định khó, để khi có xung đột lợi ích, tổ chức biết ưu tiên điều gì.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a71764b2-2289-4350-b2a9-fcd65827db6f','04-ky-nang-ca-nhan','f4b50d96-7972-4750-ad3f-c35448c1b21b',3,'Câu hỏi cốt lõi','cau-hoi-cot-loi',23,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7375980e-136a-4e2e-a67d-a07742b98509','a71764b2-2289-4350-b2a9-fcd65827db6f',37,'text','- Điều gì là lõi thống nhất không thể thay đổi trong tổ chức này?- Bộ LIGHT nào phản ánh đúng bản sắc và sứ mệnh riêng của tổ chức?- Khi có xung đột lợi ích, tổ chức sẽ ưu tiên phẩm giá hay lợi ích ngắn hạn?- Những ranh giới đạo đức nào tuyệt đối không được vượt qua?- Làm sao để toàn đội ngũ cùng sống theo một chuẩn chung?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fc3852a9-6d13-46e7-b58e-7f1be706c5f5','04-ky-nang-ca-nhan','f4b50d96-7972-4750-ad3f-c35448c1b21b',3,'Kết quả đạt được','ket-qua-at-uoc',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b4b90a74-9d85-4d0c-a17a-95743e12d88f','fc3852a9-6d13-46e7-b58e-7f1be706c5f5',38,'text','- Một hệ giá trị ONE rõ ràng, gồm **Oneness, Nobility và Ethics** và 1 bộ **LIGHT **cho riêng mình.- Bộ chuẩn hành vi cụ thể để toàn đội ngũ cùng áp dụng.- Sự đồng bộ trong nhận thức, quyết định và hành xử của tổ chức.- Một nền đạo đức vận hành đủ vững để không bị bẻ cong bởi áp lực thị trường.- Một ngọn đèn soi đường giúp tổ chức lớn lên mà không đánh mất phẩm giá và bản sắc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('10d13098-3f23-422f-8522-0de2b58a2a81','04-ky-nang-ca-nhan',NULL,2,'Xác định AWAKEN','xac-inh-awaken',25,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0491d46f-cdd4-4183-b72c-f98128d8cb02','10d13098-3f23-422f-8522-0de2b58a2a81',39,'text','AWAKEN là tầng giúp tổ chức **nhìn ra thực trạng thật** trước khi quyết định sửa gì đó. Nó dùng để phát hiện vấn đề sớm, hiểu thị trường, nhận diện lệch chuẩn và tránh việc chữa triệu chứng trong khi nguyên nhân gốc vẫn còn đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aa548568-538d-481d-9c3d-6814f52a830e','10d13098-3f23-422f-8522-0de2b58a2a81',40,'text','Trong thực hành, AWAKEN là bước “dừng lại để soi”: soi nội bộ, soi bên ngoài, soi khoảng cách, soi nguyên nhân, rồi ghi lại các tín hiệu nhỏ trước khi chúng thành khủng hoảng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('55964462-6411-4927-8275-a1d95cb80609','10d13098-3f23-422f-8522-0de2b58a2a81',41,'image',NULL,'book/04-ky-nang-ca-nhan/b47e32b1-3a76-414d-9c14-14b8f2313549-img08.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('750e3d8f-3f6b-4cbd-b0be-60910e8386e9','04-ky-nang-ca-nhan','10d13098-3f23-422f-8522-0de2b58a2a81',3,'Việc cần làm:','viec-can-lam',26,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2955eca3-404a-4b82-a447-35c679dc9d9c','04-ky-nang-ca-nhan','10d13098-3f23-422f-8522-0de2b58a2a81',3,'Cách làm cho dễ áp dụng:','cach-lam-cho-de-ap-dung',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bf8284f7-07bb-470a-ab04-37dc26eb3532','2955eca3-404a-4b82-a447-35c679dc9d9c',42,'text','- Mỗi tuần chọn 1 mảng để audit.- Mỗi vấn đề phải có 3 dòng: **hiện tượng**, **nguyên nhân gốc**, **tín hiệu sớm**.- Mỗi cuộc họp nên có 1 mục riêng: “Tuần này hệ thống đang báo hiệu điều gì?”- Không xử lý ngay bằng giải pháp; luôn hỏi “vì sao nó xảy ra”.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b105f7f4-f0fa-486b-885f-a0b8a1e4af6d','04-ky-nang-ca-nhan','10d13098-3f23-422f-8522-0de2b58a2a81',3,'Câu hỏi cốt lõi','cau-hoi-cot-loi',28,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('09cbedf6-3ba6-4504-8ea7-3fea21fbbf30','b105f7f4-f0fa-486b-885f-a0b8a1e4af6d',43,'text','Khi xác định AWAKEN, hãy dùng 6 câu hỏi này:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9abfdb5d-25c4-484a-bf06-cd32d99ab472','b105f7f4-f0fa-486b-885f-a0b8a1e4af6d',44,'text','- Tổ chức đang ở đâu?- Đang lệch chỗ nào?- Điều gì đang tác động lên mình?- Vấn đề thật nằm ở đâu?- Cơ chế nào đang tạo ra vấn đề?- Tín hiệu nhỏ nào đang báo trước rủi ro lớn hơn?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eb53ca5c-f73b-4117-b7ea-916dfb5256c5','b105f7f4-f0fa-486b-885f-a0b8a1e4af6d',45,'text','Nếu trả lời được 6 câu này, tổ chức đã bước từ phản ứng cảm tính sang phản ứng có ý thức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('73f5a289-5793-4291-acf9-0f37c81437f6','04-ky-nang-ca-nhan','10d13098-3f23-422f-8522-0de2b58a2a81',3,'Kết quả đạt được','ket-qua-at-uoc',29,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c81f6ef3-f246-47d2-8a3a-31e0ae579f12','73f5a289-5793-4291-acf9-0f37c81437f6',46,'text','Khi AWAKEN làm đúng, bạn sẽ có 4 kết quả rõ ràng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0be764f2-1d90-4b7c-b5f7-95cedef4dfc9','73f5a289-5793-4291-acf9-0f37c81437f6',47,'text','- **Nhìn thật - **Thấy đúng thực trạng thay vì nhìn bằng cảm giác.- **Hiểu gốc -** Biết nguyên nhân thật thay vì đổ lỗi cho bề mặt.- **Phát hiện sớm -** Nhận ra vấn đề trước khi nó lớn lên thành sự cố.- **Tự sửa nhanh -** Có thể điều chỉnh hệ thống trước khi thị trường buộc phải sửa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a199eb7d-ead5-40b1-980b-0de66a5b68d2','04-ky-nang-ca-nhan','10d13098-3f23-422f-8522-0de2b58a2a81',3,'Mẫu áp dụng nhanh','mau-ap-dung-nhanh',30,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3a986906-a712-4345-950f-4fd5dfe04742','a199eb7d-ead5-40b1-980b-0de66a5b68d2',48,'text','Bạn có thể dùng mẫu này cho mỗi vấn đề:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('719404b5-9ca0-4f01-a56f-5a288f42da44','a199eb7d-ead5-40b1-980b-0de66a5b68d2',49,'text','- **Hiện tượng:** ví dụ lịch hẹn trễ dần.- **Nguyên nhân gốc:** ví dụ quy trình xác nhận chưa rõ, nhân sự không có trách nhiệm chốt lịch.- **Tín hiệu sớm:** ví dụ khách nhắc lại 2–3 lần cùng một lỗi, thời gian chờ tăng nhẹ mỗi tuần.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('557f8cd5-822b-40e4-9ac6-ed1d348ffc2c','a199eb7d-ead5-40b1-980b-0de66a5b68d2',50,'text','Mẫu này giúp AWAKEN không còn là khái niệm triết lý, mà trở thành công cụ xử lý thực tế mỗi ngày',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('39f8536c-9a0b-4755-be60-fbaefaab25b5','04-ky-nang-ca-nhan',NULL,2,'Xác định DEEPEN','xac-inh-deepen',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ac20d0bb-f213-4435-83bf-0c402788ce84','39f8536c-9a0b-4755-be60-fbaefaab25b5',51,'text','Nếu AWAKEN giúp tổ chức nhìn ra sự thật, thì DEEPEN giúp tổ chức **đi vào chiều sâu của sự thật đó**. Đây là tầng mà những điều đúng không còn dừng ở mức nhận thức, mà bắt đầu được bóc tách, chuẩn hóa, đóng gói và đưa vào kỷ luật vận hành hằng ngày.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9e84affd-3c6e-493f-81da-5e4f101cceff','39f8536c-9a0b-4755-be60-fbaefaab25b5',52,'text','DEEPEN là bước chuyển từ “biết” sang “làm được một cách lặp lại”. Một tổ chức có thể nhìn ra vấn đề rất nhanh, nhưng nếu không có DEEPEN, cái nhìn ấy sẽ chỉ dừng ở ý tưởng; còn khi DEEPEN vận hành đúng, ý tưởng trở thành quy trình, quy trình trở thành thói quen, và thói quen trở thành chuẩn mực của hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5ccf694d-3977-4dcb-a138-e5b5685248d3','04-ky-nang-ca-nhan','39f8536c-9a0b-4755-be60-fbaefaab25b5',3,'Việc cần làm:','viec-can-lam',32,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6bdfb0f0-a7dd-4447-8502-48b617a9e585','04-ky-nang-ca-nhan','39f8536c-9a0b-4755-be60-fbaefaab25b5',3,'Câu hỏi cốt lõi:','cau-hoi-cot-loi',33,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('022655b9-945e-409a-ba46-35e679d2a7cf','6bdfb0f0-a7dd-4447-8502-48b617a9e585',53,'text','- Tổ chức đang cần đào sâu cái gì?- Điều đó đang yếu ở đâu: năng lực, cấu trúc hay kỷ luật thực thi?- Làm thế nào để biến cái đúng thành một quy trình có thể lặp lại?- Điều gì cần được chuẩn hóa để không phụ thuộc vào cá nhân giỏi?- Chuẩn nào cần được bảo vệ bằng kiểm soát và trách nhiệm rõ ràng?- Khi nào một chuẩn được xem là đã trở thành nếp sống của tổ chức?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('91e0ca1a-4073-4868-984e-d67493c64052','04-ky-nang-ca-nhan','39f8536c-9a0b-4755-be60-fbaefaab25b5',3,'Kết quả đạt được:','ket-qua-at-uoc',34,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4f07e4fb-f76f-4f4f-b6a9-bfb4b62739ad','91e0ca1a-4073-4868-984e-d67493c64052',54,'text','Khi DEEPEN được làm đúng, tổ chức sẽ có 4 kết quả rõ ràng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7f7fac39-8c0c-4179-b5c6-813be85471ea','91e0ca1a-4073-4868-984e-d67493c64052',55,'text','- **Năng lực được nâng chất - **Tổ chức không chỉ biết làm đúng mà còn làm đúng tốt hơn, sâu hơn và ổn định hơn.- **Quy trình được chuẩn hóa -** Những điều quan trọng được đóng gói thành SOP và không còn phụ thuộc quá nhiều vào cảm tính hoặc trí nhớ cá nhân.- **Kỷ luật được hình thành -** Chuẩn mực không còn nằm trên giấy mà đi vào thực thi bằng cơ chế rõ ràng.- **Nếp vận hành được tạo ra -** Điều đúng trở thành cách làm mặc định của hệ thống, giúp tổ chức bền hơn và ít trượt chuẩn hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0317cd8d-cf8b-4a80-b822-aff11b8fd6ae','04-ky-nang-ca-nhan',NULL,2,'Xác định MATURE','xac-inh-mature',35,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('25292b0c-436c-41c7-8dc5-a95439e47522','0317cd8d-cf8b-4a80-b822-aff11b8fd6ae',56,'text','Nếu những tầng trước giúp tổ chức nhận diện đúng, chuẩn hóa đúng và đào sâu đúng, thì MATURE là tầng giúp toàn hệ thống **bước vào trạng thái chín hơn**. Đây không chỉ là giai đoạn tổ chức lớn lên về quy mô, mà là giai đoạn nó trưởng thành hơn về nhịp, rõ hơn về chuẩn, mạnh hơn về niềm tin và linh hoạt hơn trong khả năng tự nâng cấp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('73d4b217-08fe-4730-ab29-f507503eee1d','0317cd8d-cf8b-4a80-b822-aff11b8fd6ae',57,'text','Trong thực tế, rất nhiều tổ chức có thể tăng nhanh, nhưng không phải tổ chức nào cũng chín. Có những hệ thống đi rất nhanh nhưng vẫn rời rạc, thiếu đà, thiếu sự ăn khớp giữa con người và cơ chế, thiếu niềm tin nội bộ, và thiếu năng lực tự tinh chỉnh khi môi trường thay đổi. MATURE tồn tại để xử lý chính khoảng trống đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('dc7a862d-a1bd-4e1f-955a-01a2b7c0fb5a','04-ky-nang-ca-nhan','0317cd8d-cf8b-4a80-b822-aff11b8fd6ae',3,'Việc cần làm:','viec-can-lam',36,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('32404085-5aa6-452a-a238-f81cc102755d','04-ky-nang-ca-nhan','0317cd8d-cf8b-4a80-b822-aff11b8fd6ae',3,'Câu hỏi cốt lõi:','cau-hoi-cot-loi',37,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7d7ee53a-4bde-4815-bc2b-ff3444dc64e6','32404085-5aa6-452a-a238-f81cc102755d',58,'text','- Hệ thống đã có **Momentum** chưa?- Mọi thứ đã **Attune** với nhau chưa?- Đội ngũ có **Trust** nhau chưa?- Các phần đã **Unite** thành một khối chưa?- Quy trình đã được **Refine** chưa?- Tổ chức đã sẵn sàng **Elevate** chưa?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8179d0ee-ec90-4fdf-9a2f-7ada9cb5dc24','04-ky-nang-ca-nhan','0317cd8d-cf8b-4a80-b822-aff11b8fd6ae',3,'Kết quả đạt được:','ket-qua-at-uoc',38,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d433bf1a-e60c-4ccd-b19e-8969796d181e','8179d0ee-ec90-4fdf-9a2f-7ada9cb5dc24',59,'text','Khi MATURE được làm đúng, tổ chức sẽ có 4 kết quả rõ ràng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2e38f03e-76a1-41e6-be0f-160a5f677643','8179d0ee-ec90-4fdf-9a2f-7ada9cb5dc24',60,'text','- **Có đà phát triển -** Hệ thống không còn phải khởi động lại quá nhiều lần mà bắt đầu tiến lên liên tục hơn.- **Có nhịp đồng bộ -** Mục tiêu, con người và cơ chế vận hành ăn khớp với nhau tốt hơn.- **Có niềm tin nội bộ -** Đội ngũ tin vào nhau, tin vào quy trình và tin vào khả năng chung của hệ thống.- **Có khả năng nâng tầng -** Tổ chức không chỉ giữ mức tốt hiện tại mà còn có thể đi lên một chuẩn cao hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9fd06f4a-77b8-4bdc-8908-c183fe370b4e','04-ky-nang-ca-nhan',NULL,2,'Xác định ALIGN:','xac-inh-align',39,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dbb80cbd-6bec-4618-9115-c6ffd687bedb','9fd06f4a-77b8-4bdc-8908-c183fe370b4e',61,'text','ALIGN là tầng giữ cho tổ chức không bị lệch khỏi đường ray khi bắt đầu tăng trưởng nhanh. Nếu các tầng trước giúp hệ thống hiểu đúng, chuẩn hóa đúng và trưởng thành hơn, thì ALIGN bảo đảm mọi phần của tổ chức vẫn đi cùng một hướng, cùng một nhịp và cùng một mục tiêu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a9cd139d-90ea-4954-aec6-1a62fc520e10','04-ky-nang-ca-nhan','9fd06f4a-77b8-4bdc-8908-c183fe370b4e',3,'Hành động thực hiện:','hanh-ong-thuc-hien',40,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('024945c3-e371-46a3-ae16-507cb4966482','04-ky-nang-ca-nhan','9fd06f4a-77b8-4bdc-8908-c183fe370b4e',3,'Câu hỏi cốt lõi','cau-hoi-cot-loi',41,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('179fc861-8129-448f-bfb1-27908390215e','024945c3-e371-46a3-ae16-507cb4966482',62,'text','- Mục tiêu chung của tổ chức là gì và đã được neo đủ rõ chưa?- Các nguồn lực, con người và quy trình đã thực sự nối với nhau chưa?- Khoảng lệch giữa kế hoạch và thực tế đang nằm ở đâu, và lệch bao nhiêu?- Làm sao để toàn hệ thống đi cùng một hướng, một nhịp và một chuẩn?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ad32e7d9-f768-46c8-bf49-5ce112598d34','04-ky-nang-ca-nhan','9fd06f4a-77b8-4bdc-8908-c183fe370b4e',3,'Kết quả đạt được','ket-qua-at-uoc',42,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dea851fb-ad1f-4218-bea3-93313ad43229','ad32e7d9-f768-46c8-bf49-5ce112598d34',63,'text','- Tổ chức có một mục tiêu chung đủ rõ để không bị trôi hướng.- Các bộ phận được kết nối và phối hợp như một hệ thống thống nhất.- Khoảng cách giữa chiến lược và thực thi được thu hẹp dần.- Tổ chức vận hành khớp hơn, ít lệch pha hơn và ổn định hơn khi tăng trưởng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0b1866e5-a9df-4419-842e-f012e39fdff4','04-ky-nang-ca-nhan',NULL,2,'Xác định PROSPER','xac-inh-prosper',43,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bec52f57-6415-4c41-be91-1053f9ceb466','0b1866e5-a9df-4419-842e-f012e39fdff4',64,'text','Nếu những tầng trước giúp tổ chức nhìn đúng, giữ đúng, chuẩn hóa đúng và trưởng thành hơn, thì PROSPER giúp hệ thống biến toàn bộ nền tảng đó thành đà tăng trưởng bền vững. Đây là tầng mà giá trị không chỉ được tạo ra một lần, mà tiếp tục sinh sôi, tái đầu tư và mở rộng thành nhiều vòng tăng trưởng mới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('86426456-1268-4541-b772-68a123fe85d6','0b1866e5-a9df-4419-842e-f012e39fdff4',65,'text','PROSPER là bước chuyển từ “có kết quả” sang “có hiệu ứng bánh đà”. Một tổ chức có thể tăng trưởng mà không Prosper, nhưng khi PROSPER vận hành đúng, mỗi thành quả tốt sẽ trở thành nhiên liệu cho chu kỳ tiếp theo, và hệ thống bắt đầu lớn lên theo cách tự nuôi chính mình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('75c4b924-a452-4aa9-af00-908d8ed8b2f4','04-ky-nang-ca-nhan','0b1866e5-a9df-4419-842e-f012e39fdff4',3,'Hành động cần thực hiện:','hanh-ong-can-thuc-hien',44,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('56c57fd4-a9af-4e15-8e3c-654d939c173e','04-ky-nang-ca-nhan','0b1866e5-a9df-4419-842e-f012e39fdff4',3,'Câu hỏi cốt lõi','cau-hoi-cot-loi',45,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('92dbd0a9-35d2-480a-8d25-d4c3b85ac009','56c57fd4-a9af-4e15-8e3c-654d939c173e',66,'text','- Hệ thống đang tạo ra giá trị gì có thể sinh sôi tiếp?- Thành quả hiện tại có đang được tái đầu tư đúng chỗ không?- Điều gì cần được tối ưu trước khi mở rộng?- Khi nào tổ chức đủ nền để scale mà không bị bật gốc?- Giá trị nào có thể lan truyền thành niềm tin và referral?- Hệ sinh thái đang được làm giàu theo hướng nào?- Làm sao để mỗi vòng tăng trưởng sau mạnh hơn vòng trước?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1e278346-b879-4f93-85e9-75e6e4e8e670','04-ky-nang-ca-nhan','0b1866e5-a9df-4419-842e-f012e39fdff4',3,'Kết quả đạt được','ket-qua-at-uoc',46,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('35402c89-c18c-4183-b3a2-3093af933387','1e278346-b879-4f93-85e9-75e6e4e8e670',67,'text','Khi PROSPER được làm đúng, tổ chức sẽ có 4 kết quả rõ ràng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7eb5b2d0-c7fb-4761-932e-a5d506eca240','1e278346-b879-4f93-85e9-75e6e4e8e670',68,'text','- **Giá trị được sinh sôi** - Những gì tổ chức tạo ra không dừng ở kết quả đơn lẻ mà tiếp tục lan rộng và tạo tác động mới.- **Thành quả được tái đầu tư **- Kết quả tốt trở thành nhiên liệu cho vòng tăng trưởng tiếp theo thay vì bị tiêu hao hết trong hiện tại.- **Hệ thống được mở rộng có kiểm soát** - Tổ chức lớn lên mà không mất nền, không phình to vô tổ chức và không đánh đổi sự bền vững.- **Bánh đà tăng trưởng được hình thành** - Mỗi vòng phát triển tốt sẽ làm vòng sau mạnh hơn, giúp tổ chức thịnh vượng có đà và tự nuôi chính mình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7e8c89eb-efe0-409e-b293-7da389651d92','04-ky-nang-ca-nhan',NULL,2,'WORKSHOP FORM CHO "ROOTS"','workshop-form-cho-roots',47,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2d6f5093-6fb2-47b1-987b-ef04769ea0f6','04-ky-nang-ca-nhan','7e8c89eb-efe0-409e-b293-7da389651d92',3,'Mục tiêu workshop','muc-tieu-workshop',48,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e2c8fa72-9c90-4bd3-ae1f-6d4355c4fbab','2d6f5093-6fb2-47b1-987b-ef04769ea0f6',69,'text','Giúp tổ chức trả lời rõ câu hỏi: **Chúng ta là ai, vì sao tồn tại, và đâu là gốc rễ thật sự của mình?**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8117f8f7-1188-414b-8dce-20e999972cfa','04-ky-nang-ca-nhan','7e8c89eb-efe0-409e-b293-7da389651d92',3,'Câu hỏi khai mở','cau-hoi-khai-mo',49,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3ebb6025-c6be-4ea3-ae1e-1756acb78f9c','8117f8f7-1188-414b-8dce-20e999972cfa',70,'text','- Phòng khám này sinh ra để giải quyết nỗi đau nào của thị trường?- Nếu không tồn tại phòng khám này, điều gì sẽ bị thiếu hụt?- Điều gì là lý do sâu xa nhất khiến tổ chức này phải được khai sinh?- Chúng ta muốn được nhớ đến như thế nào trong tâm trí khách hàng?- Giá trị nào không bao giờ được phép đánh đổi dù tăng trưởng có hấp dẫn đến đâu?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b668fbfd-d39e-4494-8e17-855597e5e434','04-ky-nang-ca-nhan','7e8c89eb-efe0-409e-b293-7da389651d92',3,'Câu hỏi đào sâu','cau-hoi-ao-sau',50,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ffa04b1a-1c8b-498f-8456-5bb06fb06961','b668fbfd-d39e-4494-8e17-855597e5e434',71,'text','- Đâu là bản sắc không thể sao chép của tổ chức này?- Nỗi đau cốt lõi của khách hàng mà tổ chức chọn đứng về phía họ là gì?- Nếu phải chọn giữa doanh thu nhanh và lý do tồn tại dài hạn, chúng ta chọn gì?- Điều gì là “rễ cọc”, còn điều gì chỉ là “rễ phụ” có thể thay đổi theo thời gian?- Một người mới bước vào tổ chức này cần hiểu điều gì đầu tiên về gốc rễ của nó?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5cd6fc22-c1dc-46fa-854b-d5b6e7c2e7ec','04-ky-nang-ca-nhan','7e8c89eb-efe0-409e-b293-7da389651d92',3,'Kết quả cần chốt','ket-qua-can-chot',51,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('64a2f2e5-2102-4778-86e2-bc8f59b5f36e','5cd6fc22-c1dc-46fa-854b-d5b6e7c2e7ec',72,'text','- Mission statement của phòng khám.- Một câu mô tả bản sắc gốc rễ thật ngắn gọn.- 3-5 giá trị nền không thể thỏa hiệp.- Một tuyên bố rõ ràng về nỗi đau thị trường mà tổ chức chọn giải quyết.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a12e1832-6d3a-4596-a968-6d116d9b5aef','04-ky-nang-ca-nhan',NULL,2,'WORKSHOP FORM CHO "ONE LIGHT"','workshop-form-cho-one-light',52,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('70153222-5791-4722-935c-2e97782b71c2','04-ky-nang-ca-nhan','a12e1832-6d3a-4596-a968-6d116d9b5aef',3,'Mục tiêu workshop','muc-tieu-workshop',53,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2b2a14e0-8fef-4524-9672-a18c53089cf8','70153222-5791-4722-935c-2e97782b71c2',73,'text','Giúp tổ chức xác định **một lõi bất biến** và **ánh sáng soi đường** để toàn bộ đội ngũ cùng đứng thẳng, cùng giữ chuẩn và cùng đi về một hướng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0c31166b-5515-4c38-a358-aadc9775d3a3','04-ky-nang-ca-nhan','a12e1832-6d3a-4596-a968-6d116d9b5aef',3,'Câu hỏi khai mở','cau-hoi-khai-mo',54,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cdab9ca5-201e-4211-a63a-0c376cbde5ab','0c31166b-5515-4c38-a358-aadc9775d3a3',74,'text','- Phần “một lòng” của tổ chức này là gì?- Điều gì phải thống nhất trong cách nghĩ, cách làm và cách ra quyết định của toàn đội ngũ?- Những nguyên tắc đạo đức nào là lằn ranh đỏ không được vượt qua?- Tổ chức muốn lớn lên bằng khí chất gì: cao quý, chính trực hay tiện lợi?- Điều gì là ánh sáng dẫn đường giúp đội ngũ không đi lạc khi gặp áp lực?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('64d5a3de-3036-43fa-91af-3fe0641c154a','04-ky-nang-ca-nhan','a12e1832-6d3a-4596-a968-6d116d9b5aef',3,'Câu hỏi đào sâu','cau-hoi-ao-sau',55,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4b72e63c-376c-4d2b-9e69-a777034f3d74','64d5a3de-3036-43fa-91af-3fe0641c154a',75,'text','- Chúng ta muốn nhân sự bên trong hệ thống phản ứng với nhau như thế nào khi có xung đột?- Nếu phải chọn một bộ giá trị soi đường cho mọi quyết định, đó sẽ là gì?- Điều gì làm cho tổ chức này khác với một nơi chỉ vận hành bằng lợi nhuận?- Có những hành vi nào cần được ghi rõ là “nên làm” và “không được làm”?- Làm thế nào để đạo đức không dừng ở khẩu hiệu mà đi vào thực thi?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f068bb57-7530-4b17-a3ff-d4c7e2e5a81c','04-ky-nang-ca-nhan','a12e1832-6d3a-4596-a968-6d116d9b5aef',3,'Kết quả cần chốt','ket-qua-can-chot',56,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6d16e3bd-7369-49c2-9daa-dbb63f04135f','f068bb57-7530-4b17-a3ff-d4c7e2e5a81c',76,'text','- One core principle của tổ chức.- Bộ giá trị soi đường: One Light.- Danh sách “nên làm / không được làm” cho toàn hệ thống.- Một tuyên ngôn ngắn về chuẩn mực đạo đức và khí chất vận hành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b805b210-3106-4837-8ec3-93c5be25b8c8','04-ky-nang-ca-nhan','a12e1832-6d3a-4596-a968-6d116d9b5aef',3,'Cách tổ chức buổi workshop','cach-to-chuc-buoi-workshop',57,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a5d7bdb5-b0b2-485e-8c9d-2acf8f7de7a3','b805b210-3106-4837-8ec3-93c5be25b8c8',77,'text','**Phần 1: Khai rễ**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('742e09ba-1a80-43b3-9ca1-9be55236efad','b805b210-3106-4837-8ec3-93c5be25b8c8',78,'text','Cho đội ngũ viết ra 3 câu:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('76924ecc-415a-42fc-bb0b-c98fdbf01ada','b805b210-3106-4837-8ec3-93c5be25b8c8',79,'text','- Chúng ta tồn tại để làm gì?- Chúng ta không chấp nhận đánh đổi điều gì?- Khách hàng thật sự đang đau ở đâu?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('71cf5be8-35d0-454c-ac71-fd11649d19bc','b805b210-3106-4837-8ec3-93c5be25b8c8',80,'text','**Phần 2: Chọn lõi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2aea7d3d-c436-4ac6-b0dd-e67fb88b8153','b805b210-3106-4837-8ec3-93c5be25b8c8',81,'text','Từ các câu trả lời, gom lại thành:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('46cc660a-b47c-4d4e-b7b9-6aa1e764fa77','b805b210-3106-4837-8ec3-93c5be25b8c8',82,'text','- 1 câu mission.- 1 câu core identity.- 3-5 giá trị gốc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('609f1f49-8a4f-4b78-a0ac-07e384df26b0','b805b210-3106-4837-8ec3-93c5be25b8c8',83,'text','**Phần 3: Neo ánh sáng**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('24216daa-9bae-4ebb-9d88-e8a77b3b6f1c','b805b210-3106-4837-8ec3-93c5be25b8c8',84,'text','Sau đó chốt:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('79dda31e-1982-4f1f-9264-b596239a8eac','b805b210-3106-4837-8ec3-93c5be25b8c8',85,'text','- 1 lõi bất biến của tổ chức.- 3-5 nguyên tắc soi đường.- 5-10 hành vi nên làm và không được làm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c36aaa8c-511e-41f5-979b-843a9983fbe6','b805b210-3106-4837-8ec3-93c5be25b8c8',86,'text','**Phần 4: Khóa lại**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('da315cd3-3caa-4d2e-a859-6237e2f9eb09','b805b210-3106-4837-8ec3-93c5be25b8c8',87,'text','Kết thúc bằng một câu ngắn có thể đọc to trong team meeting để nhắc toàn đội quay về ROOTS và ONE LIGHT.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('db7165ba-365f-4ef3-a866-9b018cfaf422','04-ky-nang-ca-nhan',NULL,2,'AUDIT FORM CHO "AWAKEN"','audit-form-cho-awaken',58,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4a0e1c5e-756c-4e53-a1fb-fd215a8c254e','db7165ba-365f-4ef3-a866-9b018cfaf422',88,'text','Mục tiêu: kiểm tra hệ thống đang vận hành thật sự như thế nào.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('83886156-0619-478b-b8e5-f381573a6bde','db7165ba-365f-4ef3-a866-9b018cfaf422',89,'text','Câu hỏi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('81792980-ba55-463c-b42a-7bc3cdd235b8','db7165ba-365f-4ef3-a866-9b018cfaf422',90,'text','- Thương hiệu hiện tại đang được định vị ra sao trong thực tế?- Quy trình nào đang tồn tại trên giấy nhưng không sống trong vận hành?- Điểm nào trong vận hành đang lệch so với tiêu chuẩn mong muốn?- Nhân sự đang hiểu vai trò của mình đến đâu?- Dữ liệu nào đang thiếu, sai hoặc không nhất quán?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('498c84d4-e13d-47cc-a151-193621d3bc6c','db7165ba-365f-4ef3-a866-9b018cfaf422',91,'text','Mục tiêu: quan sát môi trường bên ngoài để hiểu tổ chức đang đứng ở đâu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('47b789ca-f371-4834-b1ca-11f6de1d4897','db7165ba-365f-4ef3-a866-9b018cfaf422',92,'text','Câu hỏi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b2666b04-7b01-41ce-af41-a89cfc529a2c','db7165ba-365f-4ef3-a866-9b018cfaf422',93,'text','- Khách hàng đang thay đổi nhu cầu, kỳ vọng hay hành vi ở điểm nào?- Đối thủ đang làm tốt hơn mình ở đâu?- Xu hướng nào của thị trường đang tạo áp lực lên mô hình hiện tại?- Tổ chức đang bị thị trường kéo đi hay đang chủ động dẫn đường?- Có tín hiệu nào cho thấy định vị hiện tại đã lỗi thời hoặc cần điều chỉnh?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('61fa1579-b8d1-4b24-be5f-72e7d76d63f7','db7165ba-365f-4ef3-a866-9b018cfaf422',94,'text','Mục tiêu: vẽ rõ khoảng cách giữa thực trạng và mục tiêu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('544fd9fb-ef3d-4638-a64b-fc18e7895495','db7165ba-365f-4ef3-a866-9b018cfaf422',95,'text','Câu hỏi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8b470380-0068-4cf0-8c84-50040163035f','db7165ba-365f-4ef3-a866-9b018cfaf422',96,'text','- Hiện tại và mục tiêu đang lệch nhau ở đâu?- Khoảng cách lớn nhất nằm ở con người, quy trình, dữ liệu hay nhận thức?- Mắt xích nào đang làm chậm toàn hệ thống?- Điều gì đang tạo ra độ trễ lặp đi lặp lại?- Có khoảng cách nào đang bị xem nhẹ nhưng thực ra rất nguy hiểm?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('621f25e1-151d-44e2-b247-50a66e98a34c','db7165ba-365f-4ef3-a866-9b018cfaf422',97,'text','Mục tiêu: không dừng ở triệu chứng mà đi xuống tầng căn nguyên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('33bd54a5-70ae-4d93-917b-1428a1a4cbba','db7165ba-365f-4ef3-a866-9b018cfaf422',98,'text','Câu hỏi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bec10420-1e03-420c-88e1-08783d30cea0','db7165ba-365f-4ef3-a866-9b018cfaf422',99,'text','- Vấn đề đang xuất phát từ đâu: tư duy, cơ chế, con người hay cấu trúc?- Nếu gỡ triệu chứng ra, vấn đề gốc còn ở đó không?- Hệ thống đang lặp lại lỗi vì thiếu kỹ năng hay vì thiếu thiết kế?- Có niềm tin sai nào đang âm thầm điều khiển hành vi không?- Điều gì phải được sửa ở tầng gốc thì mới hết vòng lặp sai?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4049f14b-e8df-4878-ac9e-0bd41e208dfd','db7165ba-365f-4ef3-a866-9b018cfaf422',100,'text','Mục tiêu: nhận diện các dấu hiệu nhỏ trước khi chúng thành khủng hoảng lớn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bf936123-d6b0-49d3-9bad-6051f62a089d','db7165ba-365f-4ef3-a866-9b018cfaf422',101,'text','Câu hỏi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fe487ab6-a99b-48b8-ac1f-1193bf6b10c2','db7165ba-365f-4ef3-a866-9b018cfaf422',102,'text','- Có tín hiệu nào đang lặp lại theo mẫu không?- Điều gì đang thay đổi rất nhẹ nhưng liên tục?- Có phản hồi nào từ khách hàng, nhân sự hoặc dữ liệu đang bị bỏ qua không?- Sự cố nhỏ nào đang xuất hiện nhiều hơn bình thường?- Tín hiệu nào nếu phát hiện sớm sẽ giúp tổ chức tránh trả giá lớn hơn?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('21e585fe-0d35-4f80-8f06-c96a66cc8395','04-ky-nang-ca-nhan','db7165ba-365f-4ef3-a866-9b018cfaf422',3,'Mẫu form điền nhanh','mau-form-ien-nhanh',59,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('99e5a447-4202-4fb3-8795-2de9937e9d41','21e585fe-0d35-4f80-8f06-c96a66cc8395',103,'image',NULL,'book/04-ky-nang-ca-nhan/58d8dbfe-5023-497a-82f9-f69e7b520593-img09.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ab6f6d04-05eb-45cb-b71d-c2f928016913','04-ky-nang-ca-nhan','db7165ba-365f-4ef3-a866-9b018cfaf422',3,'Cách dùng Audit trong Workshop','cach-dung-audit-trong-workshop',60,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4a6f9278-4598-46ab-951e-cb6419ac434a','ab6f6d04-05eb-45cb-b71d-c2f928016913',104,'text','- Bước 1: Cho đội ngũ viết ra sự thật đang thấy, không tranh luận đúng sai ngay.- Bước 2: Tách dữ liệu thành 4 lớp: nội bộ, thị trường, khoảng cách, nguyên nhân gốc.- Bước 3: Chốt 3 tín hiệu sớm nguy hiểm nhất cần theo dõi tiếp.- Bước 4: Biến kết quả audit thành đầu vào cho DEEPEN.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5edebef9-d102-49a1-ac48-f5e8fb82d4e2','ab6f6d04-05eb-45cb-b71d-c2f928016913',105,'image',NULL,'book/04-ky-nang-ca-nhan/d51a8083-4e89-4de3-921d-3c0ceac3167f-img10.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b21d849c-ff7a-4268-b102-2e40186bbcdc','04-ky-nang-ca-nhan','db7165ba-365f-4ef3-a866-9b018cfaf422',3,'Câu chốt cho AWAKEN','cau-chot-cho-awaken',61,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('856357f9-97be-4557-81e9-6bddded74f27','b21d849c-ff7a-4268-b102-2e40186bbcdc',106,'text','Audit không phải để phán xét tổ chức, mà để tổ chức có đủ tỉnh táo nhìn rõ mình, nhìn rõ thị trường, và nhìn rõ điều đang âm thầm kéo mình lệch hướng. Khi audit làm đúng, AWAKEN trở thành năng lực nhìn thật trước khi buộc phải sửa thật.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3','04-ky-nang-ca-nhan',NULL,2,'SOP TEMEPLATE  CHO "DEEPEN"','sop-temeplate-cho-deepen',62,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ca765ca1-3d31-4e58-93dd-a0c061bb6d23','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',107,'text','SOP ở tầng DEEPEN không chỉ để “ghi lại cách làm”, mà để biến một năng lực đúng thành một chuẩn có thể lặp lại, chuyển giao và kiểm soát được.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f139dec4-3ef1-4814-bf3c-ffb4ad297fe3','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',108,'text','- Tên SOP:- Mã SOP:- Bộ phận áp dụng:- Người sở hữu SOP:- Người phê duyệt:- Ngày hiệu lực:- Phiên bản:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a349bfea-95e9-4ef8-9d8e-5f2b5962bb14','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',109,'text','- SOP này nhằm chuẩn hóa điều gì?- Năng lực, quy trình hoặc hành vi nào cần được đào sâu?- Kết quả cuối cùng mong muốn là gì?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7d93464b-2e4d-4c7d-a871-768cb2b1b2a2','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',110,'text','- SOP này áp dụng cho ai?- Áp dụng trong tình huống nào?- Không áp dụng cho những trường hợp nào?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('029ea92a-9631-4d37-8c79-d008ca166d37','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',111,'text','- Các thuật ngữ cần làm rõ:- Các tiêu chuẩn cần hiểu thống nhất:- Các trường hợp đặc biệt cần định nghĩa trước:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4295ed24-559f-4309-bbb1-5a52a021eab7','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',112,'text','- Nguyên tắc cốt lõi của quy trình này là gì?- Điều gì không được phép đánh đổi?- Chuẩn nào phải được giữ xuyên suốt?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b90e5f47-bc55-4911-92bf-271186027e2c','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',113,'text','- Bước 1:- Bước 2:- Bước 3:- Bước 4:- Bước 5:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('be6b4526-910b-47ce-ba81-b51c346d309c','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',114,'text','Với mỗi bước, cần có:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1adfe936-9bd0-4c68-82dd-7a8164eb1338','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',115,'text','- Mục tiêu của bước:- Người thực hiện:- Đầu vào:- Cách làm:- Đầu ra:- Tiêu chí đạt:- Lỗi thường gặp:- Cách xử lý khi có sai lệch:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a011f1e7-9b2b-4482-9ea5-b775ca01b05c','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',116,'text','- Checklist trước khi thực hiện:- Checklist trong khi thực hiện:- Checklist sau khi hoàn tất:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0d4b3d85-3546-49d3-b960-f0b2ca144b6a','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',117,'text','- Mức đạt chuẩn là gì?- Điều gì được xem là đúng?- Điều gì được xem là chưa đạt?- Có chỉ số nào dùng để đo không?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('067cfb6c-99bd-4e14-875f-2b8bb9a96fde','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',118,'text','- Ai chịu trách nhiệm chính?- Ai kiểm tra?- Ai phê duyệt?- Ai được phép xử lý ngoại lệ?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c12e13de-1c31-4a85-9a86-ed63426502ba','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',119,'text','- SOP được kiểm soát bằng cách nào?- Có audit định kỳ không?- Có KPI, checklist hoặc dashboard nào không?- Sai lệch sẽ được ghi nhận và xử lý ra sao?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dd2b41d6-4c88-40fb-841d-8ddc893182ff','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',120,'text','- Trường hợp nào được phép linh hoạt?- Ai có quyền duyệt ngoại lệ?- Ngoại lệ được ghi nhận ở đâu?- Sau ngoại lệ cần làm gì để đưa về chuẩn?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fd874c5f-c8b5-467d-8b7d-e900408642cd','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',121,'text','- Biểu mẫu đi kèm:- Checklist:- Hướng dẫn hỗ trợ:- SOP liên quan:- File dữ liệu tham chiếu:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('025f4aad-964b-4a36-bd36-06f5b5a8b14e','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',122,'text','- Phiên bản:- Ngày cập nhật:- Nội dung thay đổi:- Người cập nhật:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e95f8b75-7c71-41dc-896f-891b9d03c670','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',123,'image',NULL,'book/04-ky-nang-ca-nhan/63b35f01-93be-4c75-9ed7-c8df7b511fd0-img11.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d1e4b1fc-332d-4bdb-b576-e05245ac87fa','04-ky-nang-ca-nhan','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',3,'Cách dùng SOP Template để chuẩn hóa DEEPEN','cach-dung-sop-template-e-chuan-hoa-deepen',63,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0b3b992f-fb36-4768-a59a-744492225b78','d1e4b1fc-332d-4bdb-b576-e05245ac87fa',124,'text','- Bước 1: Chọn đúng một năng lực hoặc quy trình cần đào sâu.- Bước 2: Viết rõ mục đích, phạm vi và chuẩn đầu ra trước khi viết bước làm.- Bước 3: Bóc tách từng bước thành hành động, tiêu chí, lỗi thường gặp và cách sửa.- Bước 4: Gắn checklist, trách nhiệm và cơ chế kiểm soát để SOP không nằm trên giấy.- Bước 5: Audit lại định kỳ để chuẩn dần trở thành nếp vận hành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('92195252-3a45-4fcd-a8b7-311c567e6a8d','d1e4b1fc-332d-4bdb-b576-e05245ac87fa',125,'image',NULL,'book/04-ky-nang-ca-nhan/bc9df88f-6518-4700-a64d-2239f1cbbf0e-img12.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('76cf14d7-877d-42cc-b328-74178a0a9cab','04-ky-nang-ca-nhan','67ec5a7e-1a4c-4fcd-94e5-1f9041848ec3',3,'Câu chốt cho DEEPEN','cau-chot-cho-deepen',64,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c05d0428-fa20-4af7-9c9c-38cfd804a44c','76cf14d7-877d-42cc-b328-74178a0a9cab',126,'text','DEEPEN không dừng ở việc hiểu điều đúng, mà phải làm cho điều đúng đó trở thành một cấu trúc có thể lặp lại, kiểm soát và truyền thừa',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ffaeb9a4-a273-484e-94cc-8d8fdcd547b4','04-ky-nang-ca-nhan',NULL,2,'REVIEW SHEET CHO "MATURE"','review-sheet-cho-mature',65,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9e1d5b01-c85b-4b72-8d24-cdd0dc5986b8','ffaeb9a4-a273-484e-94cc-8d8fdcd547b4',127,'text','MATURE không chỉ là “ổn định hơn”, mà là hệ thống đã có đà, có nhịp, có trust và đang tự nâng chuẩn. Review sheet ở tầng này cần giúp tổ chức nhìn ra mức độ chín thật của vận hành, thay vì chỉ nhìn vào kết quả bề mặt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1fc04987-3ad9-48d7-b1d9-9cf112361dc9','04-ky-nang-ca-nhan','ffaeb9a4-a273-484e-94cc-8d8fdcd547b4',3,'Thông tin chung','thong-tin-chung',66,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e222ec37-74c6-4597-8a09-b545914775ef','1fc04987-3ad9-48d7-b1d9-9cf112361dc9',128,'text','- Kỳ review:- Bộ phận:- Người phụ trách:- Người review:- Mục tiêu kỳ này:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('80f92e69-be3c-4567-af55-4f4eee69d22a','1fc04987-3ad9-48d7-b1d9-9cf112361dc9',129,'text','- Hệ thống hiện có đang có đà đi lên không?- Đà đó đến từ đâu?- Có điểm nào làm đà bị chậm, gãy hoặc hụt không?- Tổ chức đang tạo momentum thật hay chỉ đang chạy theo quán tính?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0127e8da-b235-497b-95f1-c52e27239e62','1fc04987-3ad9-48d7-b1d9-9cf112361dc9',130,'text','- Các bộ phận có đang cùng nhịp không?- Nhịp làm việc giữa các vai trò có đang lệch nhau không?- Có chỗ nào cần chỉnh cadence, lịch họp, nhịp giao ban hoặc tốc độ phối hợp không?- Điều gì đang làm hệ thống thiếu đồng pha?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a38a5506-d457-4463-8f4e-72d63a6054c4','1fc04987-3ad9-48d7-b1d9-9cf112361dc9',131,'text','- Mức độ tin cậy giữa người với người ra sao?- Đội ngũ có dám nói thật, báo thật và nhận thật không?- Có bộ phận nào đang mất trust với nhau hoặc với hệ thống không?- Cơ chế nào đang giúp xây trust, và cơ chế nào đang làm trust hao mòn?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4fd9efb3-24b7-48d6-b15c-6b6cc9154ec9','1fc04987-3ad9-48d7-b1d9-9cf112361dc9',132,'text','- Các bộ phận đã thực sự hợp lực chưa?- Có tình trạng làm việc theo silo, đẩy việc hoặc ngắt kết nối không?- Nguồn lực có đang được gom về một mục tiêu chung không?- Điểm nào cần tăng liên kết giữa chức năng, vai trò và trách nhiệm?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d3dee2f8-3343-4ab7-9042-e1d0ea9c6320','1fc04987-3ad9-48d7-b1d9-9cf112361dc9',133,'text','- Quy trình nào cần được làm gọn, làm rõ hoặc làm sắc hơn?- Có điểm nào đang gây ma sát, lặp lại hoặc lãng phí năng lượng?- Hệ thống có đang quá nặng, quá rối hay quá nhiều lớp trung gian không?- Cái gì cần tinh chỉnh ngay để vận hành mượt hơn?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fe5d3339-4906-494b-81eb-786d25ee17e8','1fc04987-3ad9-48d7-b1d9-9cf112361dc9',134,'text','- Chuẩn hiện tại đã đủ cao chưa?- Tổ chức đang nâng tầng ở năng lực nào: con người, quy trình, dữ liệu hay tư duy?- Có chỉ số nào cho thấy hệ thống đang đi lên một nấc mới không?- Điều gì cần được nâng chuẩn để tạo nền cho chu kỳ trưởng thành tiếp theo?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b8d366a2-abfd-4b90-9e31-a48593c87fd0','1fc04987-3ad9-48d7-b1d9-9cf112361dc9',135,'image',NULL,'book/04-ky-nang-ca-nhan/46db1adc-d0da-4458-b18a-6623d08ab2a4-img13.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6a51f48c-0204-438b-bae7-f701585c17b1','04-ky-nang-ca-nhan','ffaeb9a4-a273-484e-94cc-8d8fdcd547b4',3,'Bảng chấm điểm mẫu','bang-cham-iem-mau',67,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('01ebaf5e-1c36-4dc1-89ee-b81c64c93b90','6a51f48c-0204-438b-bae7-f701585c17b1',136,'image',NULL,'book/04-ky-nang-ca-nhan/5d0b76e1-9ff0-48fe-8c4d-6e63059c7b71-img14.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0a9c2673-7f42-40f5-8c6c-57da44e30e9c','04-ky-nang-ca-nhan','ffaeb9a4-a273-484e-94cc-8d8fdcd547b4',3,'Câu hỏi kết luận','cau-hoi-ket-luan',68,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('556cdc0b-a0d8-45ef-8fdc-65ebc453ea65','0a9c2673-7f42-40f5-8c6c-57da44e30e9c',137,'text','- Hệ thống hiện tại đang chín ở đâu, và non ở đâu?- Điểm nghẽn lớn nhất khiến tổ chức chưa mature hơn là gì?- Điều gì cần được chỉnh ngay để tăng độ chín của toàn hệ thống?- Nếu giữ nguyên nhịp hiện tại thêm 3 tháng, hệ thống sẽ mạnh hơn hay mòn đi?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fd6cf81d-276e-4c8d-b3a5-3e7153b9aed2','04-ky-nang-ca-nhan','ffaeb9a4-a273-484e-94cc-8d8fdcd547b4',3,'Cách dùng','cach-dung',69,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('501d381d-c729-4035-80c6-d6d40687a58d','fd6cf81d-276e-4c8d-b3a5-3e7153b9aed2',138,'text','- Bước 1: Chấm từng mục theo tuần hoặc theo tháng. - Bước 2: Ghi rõ một câu sự thật cho mỗi mục, không viết chung chung.- Bước 3: Chọn ra 1-3 hành động ưu tiên để tăng độ chín của hệ thống.- Bước 4: So lại sau mỗi chu kỳ để xem hệ thống đang có thật sự mature hơn không.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0404ea80-7363-478c-9452-127d56b57f1d','fd6cf81d-276e-4c8d-b3a5-3e7153b9aed2',139,'image',NULL,'book/04-ky-nang-ca-nhan/aeaa02bd-dd42-414b-884f-4917b24b5e9d-img15.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7be2d4b9-d142-4722-aaac-c216b5751f9a','04-ky-nang-ca-nhan','ffaeb9a4-a273-484e-94cc-8d8fdcd547b4',3,'Câu chốt cho MATURE','cau-chot-cho-mature',70,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('71bbf469-6d9c-4cc0-b980-17a2cb03cf44','7be2d4b9-d142-4722-aaac-c216b5751f9a',140,'text','MATURE là tầng cho thấy tổ chức không chỉ cần chạy được, mà cần chín hơn qua từng chu kỳ. Review sheet này giúp hệ thống nhìn ra đà, nhịp, trust, hợp lực, độ sắc nét và mức nâng chuẩn của chính mình',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('73c8094d-94f5-42eb-a876-8d29efb3b73d','04-ky-nang-ca-nhan',NULL,2,'RESURCE MAP &amp; KPI CHO "ALIGN"','resurce-map-amp-kpi-cho-align',71,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ffecebf1-4108-4972-acf2-4d9b621dc506','73c8094d-94f5-42eb-a876-8d29efb3b73d',141,'text','ALIGN dùng để biến “đồng bộ” thành một năng lực có chủ đích, thay vì để các bộ phận tự chạy theo nhịp riêng. KPI/resource map ở tầng này phải cho thấy rõ mục tiêu nào cần nguồn lực nào, ai chịu trách nhiệm, và khoảng lệch đang nằm ở đâu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3b259594-48f9-4e93-854c-0a998d96b95b','04-ky-nang-ca-nhan','73c8094d-94f5-42eb-a876-8d29efb3b73d',3,'Resource map cho ALIGN','resource-map-cho-align',72,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e37971de-4e91-44ce-98d8-c8fe84e175d7','3b259594-48f9-4e93-854c-0a998d96b95b',142,'text','- Mục tiêu chiến lược:- Mục tiêu vận hành:- Mục tiêu con người:- Mục tiêu dữ liệu:- Mục tiêu chất lượng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d63429c7-1ac6-43a6-a308-3511042926a0','3b259594-48f9-4e93-854c-0a998d96b95b',143,'text','- Nhân sự chủ chốt:- Năng lực còn thiếu:- Công cụ và hệ thống:- Ngân sách:- Thời gian:- Dữ liệu đầu vào:- Quyền quyết định:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a00885b6-c6e2-4018-8172-a26d774c08a4','3b259594-48f9-4e93-854c-0a998d96b95b',144,'text','- Mục tiêu nào đang phụ thuộc vào nguồn lực nào?- Nguồn lực nào đang bị trùng, thiếu hoặc nghẽn?- Bộ phận nào cần nối chặt hơn với bộ phận nào?- Điểm nào đang làm đứt dòng thông tin?- Nơi nào đang có quá nhiều người nhưng thiếu trách nhiệm rõ?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f17e5f40-8948-4bc6-bea4-bc100342b7c7','3b259594-48f9-4e93-854c-0a998d96b95b',145,'image',NULL,'book/04-ky-nang-ca-nhan/dd47fbd2-115f-4551-a436-8c5ca8ca5fe2-img16.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b68607e7-5324-48cf-bf38-ef8af3dfe1a3','04-ky-nang-ca-nhan','73c8094d-94f5-42eb-a876-8d29efb3b73d',3,'KPI cho ALIGN','kpi-cho-align',73,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('37ca43b7-ae4b-4c92-888b-4225f1df0c86','b68607e7-5324-48cf-bf38-ef8af3dfe1a3',146,'text','Dùng để kiểm tra mục tiêu đã được neo đủ rõ hay chưa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('03e9e2ad-9bbd-4a84-aedd-80eef13d7d77','b68607e7-5324-48cf-bf38-ef8af3dfe1a3',147,'text','- Tỷ lệ mục tiêu có owner rõ ràng.- Tỷ lệ mục tiêu có deadline rõ ràng.- Tỷ lệ mục tiêu có tiêu chí hoàn thành rõ ràng.- Tỷ lệ đội ngũ hiểu đúng ưu tiên chiến lược.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('69f5f796-b1d8-4f59-8507-cb40bb7ed297','b68607e7-5324-48cf-bf38-ef8af3dfe1a3',148,'text','Dùng để đo mức độ kết nối nguồn lực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4e799f2f-fe97-4904-a21f-78765014589d','b68607e7-5324-48cf-bf38-ef8af3dfe1a3',149,'text','- Tỷ lệ đầu việc có người phụ trách và người phối hợp.- Tỷ lệ bàn giao đúng hạn giữa các bộ phận.- Số điểm nghẽn luồng thông tin.- Thời gian phản hồi giữa các phòng ban.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4e6d491d-0613-4f31-9e96-cfe15b0979f6','b68607e7-5324-48cf-bf38-ef8af3dfe1a3',150,'text','Dùng để kiểm tra mức độ tích hợp hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c2bac3ac-823c-4968-9f7e-9c3ad5d83004','b68607e7-5324-48cf-bf38-ef8af3dfe1a3',151,'text','- Tỷ lệ quy trình liên phòng ban đã được chuẩn hóa.- Tỷ lệ dữ liệu được đồng bộ trên cùng một nguồn.- Tỷ lệ công cụ quản trị đang dùng chung.- Mức độ lệch giữa kế hoạch và thực thi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6c7676dc-dd55-4579-88ae-828cd4ac11ad','b68607e7-5324-48cf-bf38-ef8af3dfe1a3',152,'text','Dùng để đo năng lực quản trị nhịp vận hành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('747575de-ea32-4edf-ac67-5b0fec437f2e','b68607e7-5324-48cf-bf38-ef8af3dfe1a3',153,'text','- Số buổi review định kỳ được thực hiện đúng lịch.- Tỷ lệ quyết định lớn có dữ liệu hỗ trợ.- Tỷ lệ việc được xử lý đúng thẩm quyền.- Tỷ lệ vấn đề lặp lại sau khi đã có cơ chế xử lý.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('12108701-c9a2-4c09-badf-fa3df590d26a','b68607e7-5324-48cf-bf38-ef8af3dfe1a3',154,'text','Dùng để theo dõi việc thu hẹp khoảng lệch.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ce68ef0b-08c0-4d75-952c-d3068f0e7960','b68607e7-5324-48cf-bf38-ef8af3dfe1a3',155,'text','- Khoảng cách giữa kế hoạch và thực tế.- Khoảng cách giữa mục tiêu và năng lực hiện tại.- Khoảng cách giữa bộ phận A và bộ phận B trong phối hợp.- Khoảng cách giữa chuẩn mong muốn và chuẩn thực thi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('98b183e8-ad4f-4b13-b3d7-44f4a244fb24','b68607e7-5324-48cf-bf38-ef8af3dfe1a3',156,'image',NULL,'book/04-ky-nang-ca-nhan/b287a4ea-6d1a-485e-abeb-417993c009ac-img17.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('21fcdee1-e875-4c6d-8cb7-8ea68708542a','04-ky-nang-ca-nhan','73c8094d-94f5-42eb-a876-8d29efb3b73d',3,'Cách dùng KPI cho ALIGN','cach-dung-kpi-cho-align',74,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('10d2fa63-9917-4851-a0e7-17eee8559706','21fcdee1-e875-4c6d-8cb7-8ea68708542a',157,'text','- Bước 1: Chốt 3-5 mục tiêu trọng yếu của kỳ.- Bước 2: Gắn mỗi mục tiêu với một owner, một nhóm nguồn lực và một KPI chính.- Bước 3: Đánh dấu chỗ thiếu nguồn lực, chỗ dư nguồn lực và chỗ đang lệch nhịp.- Bước 4: Review định kỳ để thu hẹp khoảng lệch giữa kế hoạch và thực tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6848b671-b661-4119-847d-dfa6795f38cd','21fcdee1-e875-4c6d-8cb7-8ea68708542a',158,'image',NULL,'book/04-ky-nang-ca-nhan/e10d5194-e46c-4fc8-9041-df07c6fc43c1-img18.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3b0edbda-bdb7-4684-b150-3c79494186c8','04-ky-nang-ca-nhan','73c8094d-94f5-42eb-a876-8d29efb3b73d',3,'Câu chốt cho ALIGN','cau-chot-cho-align',75,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7e468d6f-a029-49e8-8eb8-3983adbfd5db','3b0edbda-bdb7-4684-b150-3c79494186c8',159,'text','ALIGN không chỉ là phân bổ nguồn lực, mà là làm cho mục tiêu, con người, dữ liệu và cơ chế cùng hướng về một trục vận hành duy nhất. KPI/resource map giúp tổ chức nhìn thấy rõ mình đang lệch ở đâu để siết lại đúng chỗ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('283124c9-1a67-4006-8a22-8652de51d02b','04-ky-nang-ca-nhan',NULL,2,'GROWTH LOOP CANVAS CHO "PROSPER"','growth-loop-canvas-cho-prosper',76,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7399de14-7fe6-4403-bdcd-bac4d4d11430','04-ky-nang-ca-nhan','283124c9-1a67-4006-8a22-8652de51d02b',3,'Mục tiêu PROSPER','muc-tieu-prosper',77,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7a692eca-3dad-43dc-aded-30197c68b259','7399de14-7fe6-4403-bdcd-bac4d4d11430',160,'text','PROSPER không chỉ là tăng trưởng một lần, mà là tạo ra một vòng lặp giúp thành quả hiện tại sinh ra lực cho chu kỳ tiếp theo. Canvas này giúp tổ chức nhìn rõ đầu ra nào sẽ được tái đầu tư, giá trị nào sẽ lan truyền, và hệ nào cần được làm mới để không bị già hóa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cd9db2d0-1d8d-4cb7-9fbc-9afeebd5334e','7399de14-7fe6-4403-bdcd-bac4d4d11430',161,'text','- Giá trị nào đang sinh sôi mạnh nhất?- Thành quả nào có thể nhân bản?- Điều gì đang tạo ra tác động lan rộng tự nhiên?- Nguồn lực nào đang tạo ra hiệu ứng cộng hưởng?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8ca8cf51-524c-4f0a-bb13-bea20af717a9','7399de14-7fe6-4403-bdcd-bac4d4d11430',162,'text','- Lợi nhuận, dữ liệu, niềm tin hoặc thời gian nên tái đầu tư vào đâu?- Cái gì cần quay lại nuôi con người, quy trình, nội dung hoặc hạ tầng?- Tái đầu tư nào tạo tác động dài hạn nhất?- Phần nào không được tiêu dùng hết trong hiện tại?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7e488e80-7951-481b-91a5-ab071e9fc3bb','7399de14-7fe6-4403-bdcd-bac4d4d11430',163,'text','- Chỗ nào đang tạo ma sát?- Chỗ nào đang lãng phí nguồn lực?- Nút thắt nào cần được tinh chỉnh để vòng lặp chạy nhẹ hơn?- Điều gì cần chuẩn hóa hoặc tự động hóa?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a728a532-fe4a-4928-879c-ff15947dfa2e','7399de14-7fe6-4403-bdcd-bac4d4d11430',164,'text','- Hệ thống đã đủ chắc để mở rộng chưa?- Mở rộng ở đâu sẽ tạo đòn bẩy lớn nhất?- Điều gì có thể nhân bản mà không làm giảm chất lượng?- Nguồn lực nào cần được tăng trước khi scale?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('123c3cd4-f5e2-48e6-9cb6-00697200e902','7399de14-7fe6-4403-bdcd-bac4d4d11430',165,'text','- Giá trị nào có thể lan qua referral, cộng đồng hoặc truyền miệng?- Cơ chế nào làm cho niềm tin tự lan rộng?- Nội dung, trải nghiệm hay kết quả nào có sức truyền nhiễm cao?- Ai là nhóm khuếch tán giá trị mạnh nhất?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5c336781-d22e-498c-9fe3-4af9aabfd71c','7399de14-7fe6-4403-bdcd-bac4d4d11430',166,'text','- Hệ sinh thái nào cần được làm giàu?- Dữ liệu nào nên thu lại để tạo hiểu biết mới?- Kinh nghiệm nào có thể đóng gói thành tài sản?- Tài nguyên nào sẽ làm sâu thêm năng lực hệ thống?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('66d4bb9e-4415-473c-a7e1-d1d7927452a9','7399de14-7fe6-4403-bdcd-bac4d4d11430',167,'text','- Điều gì cần được làm mới để tránh cũ hóa?- Mô hình nào đã thành công nhưng đang bắt đầu mòn?- Năng lực nào cần tái tạo cho chu kỳ tiếp theo?- Chu kỳ nào phải quay lại ROOTS để tái căn bản hóa?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8fcca904-f081-4c96-8e54-d76f5d2c3b00','04-ky-nang-ca-nhan','283124c9-1a67-4006-8a22-8652de51d02b',3,'Bản map mẫu GROWTH LOOP CANVAS','ban-map-mau-growth-loop-canvas',78,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1017b7cb-e5a1-4dc5-8e6b-121641c8ef9c','8fcca904-f081-4c96-8e54-d76f5d2c3b00',168,'image',NULL,'book/04-ky-nang-ca-nhan/b6029b4d-65a9-4d33-a3a0-f7ad27dee175-img19.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('75a7db25-cfcb-402e-bc2a-65a11c917b88','04-ky-nang-ca-nhan','283124c9-1a67-4006-8a22-8652de51d02b',3,'Câu hỏi thiết kế','cau-hoi-thiet-ke',79,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c75ec915-3a19-438e-a9de-0c012654b8ec','75a7db25-cfcb-402e-bc2a-65a11c917b88',169,'text','- Cái gì là **hạt giống tăng trưởng** hiện tại?- Đâu là **nguồn lực tốt nhất để tái đầu tư**?- Nút thắt lớn nhất đang nằm ở đâu: nhân sự, quy trình, dữ liệu hay thị trường?- Điều gì có thể trở thành **đòn bẩy nhân bản**?- Hệ thống cần làm mới phần nào trước khi vòng sau bắt đầu?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fc4f4784-4377-4000-b31e-b063074c96f8','04-ky-nang-ca-nhan','283124c9-1a67-4006-8a22-8652de51d02b',3,'Chỉ số theo dõi PROSPER','chi-so-theo-doi-prosper',80,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b0b1b4ec-c1b9-4443-a67a-aa305e93e144','fc4f4784-4377-4000-b31e-b063074c96f8',170,'text','- Tỷ lệ giá trị được nhân bản:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e16ad5fa-7b40-4d1f-8dbd-9c421ae0c3d3','fc4f4784-4377-4000-b31e-b063074c96f8',171,'text','Chỉ số này đo phần giá trị cốt lõi đã được biến từ một trường hợp tốt thành nhiều trường hợp tốt hơn.
Công thức gợi ý: số case/điểm chạm/chi nhánh/đội ngũ áp dụng được chuẩn giá trị cốt lõi chia cho tổng số case/điểm chạm/chi nhánh/đội ngũ liên quan.
Ví dụ: một SOP tư vấn tốt được áp dụng đồng nhất ở 4/5 cơ sở thì tỷ lệ nhân bản là 80%.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6d130dce-dca1-4829-b412-0eb8b9f9bdc9','fc4f4784-4377-4000-b31e-b063074c96f8',172,'text','- Tỷ lệ nguồn lực tái đầu tư:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('602489ac-e9ca-4e12-af89-a688355f5589','fc4f4784-4377-4000-b31e-b063074c96f8',173,'text','Chỉ số này đo bao nhiêu phần thành quả hiện tại được quay lại nuôi cho con người, quy trình, dữ liệu, công nghệ hoặc thương hiệu.
Công thức gợi ý: giá trị tái đầu tư chia cho tổng giá trị tạo ra trong kỳ.
Nếu lợi nhuận có tăng nhưng không có phần nào quay lại nâng nền hệ thống, PROSPER sẽ chỉ là tăng trưởng ngắn hạn chứ chưa thành vòng lặp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('492f15de-941f-4e8c-9fab-303fea638b00','fc4f4784-4377-4000-b31e-b063074c96f8',174,'text','- Tỷ lệ ma sát được loại bỏ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a8e1a189-d148-42b0-8859-47f3094d6383','fc4f4784-4377-4000-b31e-b063074c96f8',175,'text','Chỉ số này đo mức độ hệ thống đang nhẹ hơn, mượt hơn và ít lãng phí hơn so với trước.
Công thức gợi ý: số điểm nghẽn đã xử lý chia cho tổng số điểm nghẽn đã ghi nhận, hoặc đo bằng thời gian chờ, số lỗi lặp, số bước thừa trước và sau tối ưu.
Ma sát càng giảm đều, hệ thống càng có thêm năng lực để mở rộng mà không tự làm nặng mình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('127f6aaa-5719-4150-8c78-f2b0bd557add','fc4f4784-4377-4000-b31e-b063074c96f8',176,'text','- Tốc độ mở rộng có kiểm soát:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e3e19f9e-b115-4896-a8da-a3cb9e0120b4','fc4f4784-4377-4000-b31e-b063074c96f8',177,'text','Chỉ số này đo mức độ scale đang diễn ra đúng nhịp, đúng nền và đúng năng lực.
Công thức gợi ý: mức tăng quy mô thực tế so với mức tăng năng lực nền tương ứng, theo từng kỳ.
Một hệ thống mở rộng nhanh hơn năng lực kiểm soát sẽ tạo ra tăng trưởng “phình” chứ không phải tăng trưởng bền.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7d96e828-8385-492e-8cc0-c2af148dc5b4','fc4f4784-4377-4000-b31e-b063074c96f8',178,'text','- Tỷ lệ lan truyền tự nhiên:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('811516bf-8d42-4160-924c-e5e50a89f9b1','fc4f4784-4377-4000-b31e-b063074c96f8',179,'text','Chỉ số này đo mức độ giá trị đang được truyền đi qua referral, cộng đồng, giới thiệu hoặc hiệu ứng niềm tin, thay vì chỉ phụ thuộc vào chi phí kéo traffic.
Công thức gợi ý: số khách/đầu mối đến từ giới thiệu, truyền miệng hoặc cộng đồng chia cho tổng số khách/đầu mối trong kỳ.
Tỷ lệ này càng cao thì hệ thống càng có sức lan truyền thật, không cần tiêu hao quá nhiều để mua sự chú ý.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bb024b5e-b694-4686-bb02-c5a723313cad','fc4f4784-4377-4000-b31e-b063074c96f8',180,'text','- Mức độ làm giàu hệ sinh thái:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fc3b5ddd-b633-4325-a991-f6f297d56f7a','fc4f4784-4377-4000-b31e-b063074c96f8',181,'text','Chỉ số này đo hệ thống có đang sâu hơn, nhiều lớp hơn và có giá trị tích lũy hơn không.
Công thức gợi ý: số tài sản mới được tạo ra trong hệ sinh thái, như dữ liệu, tri thức, cộng đồng, đối tác, quy trình, nội dung, chia theo số nhóm tài sản mục tiêu.
Nếu chỉ doanh thu tăng mà hệ sinh thái không giàu thêm, tổ chức vẫn chưa thật sự prosper.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bb8802da-24b1-40b1-9d05-65691cb758a0','fc4f4784-4377-4000-b31e-b063074c96f8',182,'text','- Tỷ lệ làm mới chu kỳ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c04ff42c-002f-473f-b630-ab2487f71795','fc4f4784-4377-4000-b31e-b063074c96f8',183,'text','Chỉ số này đo khả năng hệ thống tự làm mới để không bị cũ hóa sau một vòng thành công.
Công thức gợi ý: số cải tiến, mô hình mới, chuẩn mới hoặc cơ chế mới được kích hoạt trong chu kỳ chia cho tổng số hạng mục cần renew.
Renew không phải thay đổi cho vui, mà là làm mới có chủ đích để vòng sau mạnh hơn vòng trước.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e129769a-95df-479d-a0b1-61b9f72a1db4','fc4f4784-4377-4000-b31e-b063074c96f8',184,'image',NULL,'book/04-ky-nang-ca-nhan/bfa5b81b-4aec-423b-8f2c-3eda9dac5c6f-img20.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('75645c73-c8f1-45ca-93b0-cef41953ec30','04-ky-nang-ca-nhan','283124c9-1a67-4006-8a22-8652de51d02b',3,'Câu chốt cho PROSPER','cau-chot-cho-prosper',81,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bc38966b-d35d-4d52-b131-4c8ab74d5d22','75645c73-c8f1-45ca-93b0-cef41953ec30',185,'text','PROSPER là tầng biến tăng trưởng thành một hệ sinh thái tự sinh sôi, tự tái đầu tư và tự làm mới. Khi vòng lặp này chạy đúng, tổ chức không chỉ lớn hơn, mà còn giàu hơn về niềm tin, sâu hơn về năng lực và bền hơn về tương lai.',NULL,NULL,NULL,NULL,NULL);
